// Package apidoc keeps a registry of Go struct doc comments used to enrich
// the generated OpenAPI document.
//
// Code generated by gg registers struct and field comments at build time so
// the running binary can describe schema fields even when Go source files are
// not available, eg. in a container image that only ships the compiled binary.
package apidoc

import (
	"maps"
	"slices"
	"strings"
	"sync"
)

// StructDoc holds the doc comments of a single struct.
type StructDoc struct {
	// Comment is the doc comment of the struct itself.
	Comment string
	// Fields maps a Go field name to its doc comment.
	Fields map[string]string
}

// EnumValue describes one declared constant of an enum-like named type.
type EnumValue struct {
	// Value is the constant literal as it appears in JSON, eg. "fixed_odds" or 2.
	Value any
	// Comment is the doc comment of the constant.
	Comment string
}

// EnumDoc holds the doc comment and declared values of an enum-like named
// type, eg. `type PayoutRuleType string` with a const block of its values.
type EnumDoc struct {
	// Comment is the doc comment of the type itself.
	Comment string
	// Values lists the declared constants in source order.
	Values []EnumValue
}

var (
	mu           sync.RWMutex
	registry     = make(map[string]StructDoc)
	enumRegistry = make(map[string]EnumDoc)

	// signatureRegistry maps a struct's field-name signature to its field
	// docs, so an anonymous struct (a type alias to an unnamed struct, which
	// reflection cannot resolve to a package path and type name) can recover
	// its field docs by structural signature. signatureAmbiguous records
	// signatures shared by structs with differing field docs; such signatures
	// are dropped so a lookup never returns docs belonging to another struct.
	signatureRegistry  = make(map[string]map[string]string)
	signatureAmbiguous = make(map[string]bool)
)

func registryKey(pkgPath, typeName string) string {
	return pkgPath + "." + typeName
}

// Register records the doc comments for the struct identified by pkgPath and
// typeName. Registering the same struct again replaces the previous entry.
// The Fields map is copied, so callers may reuse it after Register returns.
func Register(pkgPath, typeName string, doc StructDoc) {
	doc.Fields = maps.Clone(doc.Fields)

	mu.Lock()
	defer mu.Unlock()
	registry[registryKey(pkgPath, typeName)] = doc
	indexFieldsBySignature(doc.Fields)
}

// Lookup returns the doc comments registered for the struct identified by
// pkgPath and typeName. The returned StructDoc owns its Fields map, so
// callers may mutate it freely.
func Lookup(pkgPath, typeName string) (StructDoc, bool) {
	mu.RLock()
	defer mu.RUnlock()

	doc, ok := registry[registryKey(pkgPath, typeName)]
	if !ok {
		return StructDoc{}, false
	}
	doc.Fields = maps.Clone(doc.Fields)
	return doc, true
}

// fieldNameSignature builds a stable signature from a set of Go field names.
func fieldNameSignature(names []string) string {
	names = slices.Clone(names)
	slices.Sort(names)
	return strings.Join(names, "\n")
}

// indexFieldsBySignature records fields under their field-name signature.
// Callers must hold mu. When two structs with differing field docs share a
// signature it is marked ambiguous and removed, so a later signature lookup
// returns nothing rather than the wrong struct's docs.
func indexFieldsBySignature(fields map[string]string) {
	if len(fields) == 0 {
		return
	}
	sig := fieldNameSignature(slices.Collect(maps.Keys(fields)))
	if signatureAmbiguous[sig] {
		return
	}
	if existing, ok := signatureRegistry[sig]; ok {
		if !maps.Equal(existing, fields) {
			signatureAmbiguous[sig] = true
			delete(signatureRegistry, sig)
		}
		return
	}
	signatureRegistry[sig] = fields
}

// LookupFieldsBySignature returns the field docs of a registered struct whose
// documented field-name set equals names. It serves anonymous structs (type
// aliases to unnamed structs) that cannot be identified by package path and
// type name. It returns false when there is no match or the signature is
// shared by structs with differing docs.
func LookupFieldsBySignature(names []string) (map[string]string, bool) {
	sig := fieldNameSignature(names)

	mu.RLock()
	defer mu.RUnlock()

	if signatureAmbiguous[sig] {
		return nil, false
	}
	fields, ok := signatureRegistry[sig]
	if !ok {
		return nil, false
	}
	return maps.Clone(fields), true
}

// RegisterEnum records the doc comment and declared values of the enum-like
// type identified by pkgPath and typeName. Registering the same type again
// replaces the previous entry. The Values slice is copied, so callers may
// reuse it after RegisterEnum returns.
func RegisterEnum(pkgPath, typeName string, doc EnumDoc) {
	doc.Values = slices.Clone(doc.Values)

	mu.Lock()
	defer mu.Unlock()
	enumRegistry[registryKey(pkgPath, typeName)] = doc
}

// LookupEnum returns the enum doc registered for the type identified by
// pkgPath and typeName. The returned EnumDoc owns its Values slice, so
// callers may mutate it freely.
func LookupEnum(pkgPath, typeName string) (EnumDoc, bool) {
	mu.RLock()
	defer mu.RUnlock()

	doc, ok := enumRegistry[registryKey(pkgPath, typeName)]
	if !ok {
		return EnumDoc{}, false
	}
	doc.Values = slices.Clone(doc.Values)
	return doc, true
}
